const query = $input.first().json.query || {};
const expectedToken = $env.FACEBOOK_WEBHOOK_VERIFY_TOKEN || 'CONFIG_FACEBOOK_WEBHOOK_VERIFY_TOKEN';
const mode = query['hub.mode'];
const token = query['hub.verify_token'];
const challenge = query['hub.challenge'];

if (mode === 'subscribe' && token === expectedToken && challenge) {
  return [{ json: { response: challenge, code: 200 } }];
}

return [{ json: { response: 'Forbidden', code: 403 } }];

const items = $input.all();
const result = [];

let staticData = {};
try {
  const fs = require('fs');
  const path = require('path');
  const filePath = path.join($env.N8N_USER_FOLDER || './.n8n', 'processed_facebook_ids.json');
  if (fs.existsSync(filePath)) {
    staticData = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  }
} catch (e) {
  staticData = $getWorkflowStaticData('global');
}
staticData.processedIds = staticData.processedIds || [];

function saveStaticData(data) {
  try {
    const fs = require('fs');
    const path = require('path');
    const filePath = path.join($env.N8N_USER_FOLDER || './.n8n', 'processed_facebook_ids.json');
    fs.mkdirSync(path.dirname(filePath), { recursive: true });
    fs.writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf8');
  } catch (e) {
    // fallback
  }
}

if (staticData.processedIds.length > 200) {
  staticData.processedIds = staticData.processedIds.slice(-100);
}

for (const item of items) {
  const body = item.json.body;
  const entries = body?.entry || [];

  for (const entry of entries) {
    for (const msg of entry.messaging || []) {
      const msgId = msg.message?.mid;
      const senderId = msg.sender?.id;
      const text = msg.message?.text;
      if (!msgId || !senderId || !text || staticData.processedIds.includes(msgId)) continue;
      staticData.processedIds.push(msgId);
      result.push({ json: { source: 'messenger', senderId, text, eventId: msgId } });
    }

    for (const changeItem of entry.changes || []) {
      const change = changeItem.value || {};
      const commentId = change.comment_id || change.id;
      const text = change.message;
      const senderId = change.from?.id;
      if (change.item !== 'comment' || change.verb !== 'add' || !commentId || !text || staticData.processedIds.includes(commentId)) continue;
      staticData.processedIds.push(commentId);
      result.push({ json: { source: 'comment', commentId, senderId, text, eventId: commentId } });
    }
  }
}

saveStaticData(staticData);
return result;

const source = $node['Deduplication & Parse'].json.source;
const text = $node['Deduplication & Parse'].json.text || '';
const output = $json.output || $json.text || '';
const lower = text.toLowerCase();
const isDeal = /(chốt|chot|đặt|dat|mua|order|sđt|sdt|số điện thoại|so dien thoai|địa chỉ|dia chi)/i.test(lower);
const phone = (text.match(/(\+?84|0)\d{8,10}/) || [])[0] || '';
const product = (text.match(/(?:mua|đặt|dat|order|chốt|chot)\s+([^,.;\n]+)/i) || [])[1]?.trim() || '';
const address = (text.match(/(?:địa chỉ|dia chi|ship tới|giao tới)[:\s]+([^\n]+)/i) || [])[1]?.trim() || '';

// Try to pull image_urls from tool output if AI Agent called Product Image Lookup tool.
const toolResp = $json.tool_response || $json.toolResponse || $json.image_urls || null;
let imageUrls = [];
if (Array.isArray(toolResp)) imageUrls = toolResp;
else if (toolResp && Array.isArray(toolResp.image_urls)) imageUrls = toolResp.image_urls;
else if (toolResp && Array.isArray(toolResp.files)) imageUrls = toolResp.files;

const primaryUrl = imageUrls.length > 0
  ? (imageUrls[0].url || imageUrls[0].webViewLink || imageUrls[0])
  : null;

return [{
  json: {
    source,
    senderId: $node['Deduplication & Parse'].json.senderId,
    commentId: $node['Deduplication & Parse'].json.commentId,
    eventId: $node['Deduplication & Parse'].json.eventId,
    text,
    ai_reply: output,
    is_deal: isDeal,
    customer_name: '',
    phone,
    address,
    product,
    image_urls: imageUrls,
    primary_image_url: typeof primaryUrl === 'string' ? primaryUrl : (primaryUrl && primaryUrl.url) || null,
    has_image: !!primaryUrl,
    captured_at: new Date().toISOString()
  }
}];
